export type MarkdownRenderContext = {
  locale: string;
};

// 调用方保证 locale 已完成决策；backend 不做自动推断

type HtmlLocaleSelection =
  | { mode: "all" }
  | { mode: "single"; locale: string };

export type HtmlRenderContext = {
  localeSelection: HtmlLocaleSelection;
  themePreset?: ThemePreset;
  colorMode?: ThemeMode;
  interactive?: boolean;
  rendererRoot?: string;
};

export type LocaleResolutionInput = {
  mode: "dashboard-empty" | "dashboard-doc" | "html-all" | "html-single";
  rendererLocales: readonly string[];
  rendererDefaultLocale: string;
  docLocales?: readonly string[];
  docDefaultLocale?: string;
  singleLocale?: string;
  storedUiLocale?: string | null;
  browserLocales: readonly string[];
};

export type LocaleResolutionOutput = {
  availableLocales: readonly string[];
  contentLocale: string;
  uiLocale: string;
  shouldPersistUiLocale: boolean;
};
